mapper.select:
SELECT r.raw_transaction_id AS rawTransactionId, r.source_key AS sourceKey, r.property_type AS propertyType, r.transaction_type AS transactionType, r.sido, r.sigungu, r.legal_dong AS legalDong, r.jibun, r.full_address AS fullAddress, r.apartment_name AS apartmentName, r.exclusive_area_m2 AS exclusiveAreaM2, r.floor, r.built_year AS builtYear, r.deal_date AS dealDate, r.deal_amount_krw AS dealAmountKrw, r.deposit_amount_krw AS depositAmountKrw, r.monthly_rent_krw AS monthlyRentKrw, r.geocoding_status AS geocodingStatus, g.status AS geocodingCacheStatus, g.latitude, g.longitude FROM public_data_raw_apartment_transactions r INNER JOIN public_data_geocoding_cache g ON g.address_key = r.address_key WHERE r.geocoding_status = 'SUCCESS' AND g.status = 'SUCCESS' AND g.latitude IS NOT NULL AND g.longitude IS NOT NULL AND r.canonical_status IN ('NOT_READY', 'ELIGIBLE', 'FAILED')
AND r.import_run_id = #{importRunId}
ORDER BY r.raw_transaction_id ASC

SELECT p.property_id
FROM properties p
WHERE (
      p.property_type = #{propertyType}
      OR (#{propertyType} = 'OFFICETEL' AND p.property_type = 'APARTMENT')
  )
  AND p.sido = #{sido}
  AND p.sigungu = #{sigungu}
  AND p.legal_dong = #{legalDong}
  AND p.jibun_address = #{fullAddress}
  AND p.name = #{apartmentName}
ORDER BY CASE
    WHEN #{propertyType} = 'OFFICETEL' AND p.property_type = 'APARTMENT' THEN 0
    WHEN p.property_type = #{propertyType} THEN 1
    ELSE 2
END,
p.property_id ASC
LIMIT 1
